from flask import Flask, jsonify
from pymemcache.client import base

app = Flask(__name__)
mem_client = base.Client(('localhost', 11211))

def get_cached_data(key):
    return mem_client.get(key)

def set_cached_data(key, data, ttl=300):
    mem_client.set(key, data, expire=ttl)

# Example database query function (replace with actual DB query logic)
def fetch_user(user_id):
    # Simulate a database query
    user_data = {"id": user_id, "name": "John Doe", "email": "john.doe@example.com"}
    return user_data

@app.route('/user/<int:user_id>', methods=['GET'])
def get_user(user_id):
    cache_key = f'user_{user_id}'
    cached_data = get_cached_data(cache_key)
    
    if cached_data is not None:
        return jsonify(cached_data), 200
    
    user_data = fetch_user(user_id)
    set_cached_data(cache_key, user_data, ttl=3600)  # Cache for 1 hour
    
    return jsonify(user_data), 200

if __name__ == '__main__':
    app.run(debug=True)